module lfsr(
    input wire reset_clk,
    input wire rst,
    output reg [11:0] lfsr_out
);

always @(posedge reset_clk) begin
    if (rst) begin
        lfsr_out <= 12'b000000000001;
    end else begin
        lfsr_out <= {lfsr_out[10:0], lfsr_out[11] ^ lfsr_out[3]};
    end
end

endmodule
